#include <stdio.h>
int main() {
    int T, N, i, j;
    int A[100005], B[100005];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int operations = 0;
        for (i = 0; i < N; i++) {
            if (A[i] > B[i]) {
                int min_height = B[i];
                for (j = i; j >= 0; j--) {
                    if (A[j] < min_height) {
                        break;
                    }
                    A[j] = min_height;
                }
                operations++;
            }
        }
        printf("%d\n", operations);
    }
    return 0;
}

