        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = scanner.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = scanner.nextInt();
            }
            int operations = 0;
            for (int i = 0; i < N; i++) {
                if (A[i] > B[i]) {
                    int min_height = B[i];
                    for (int j = i; j >= 0; j--) {
                        if (A[j] < min_height) {
                            break;
                        }
                        A[j] = min_height;
